
# src/plot_results.py
# Plot training curves from results.csv (auto-generated by YOLO)
# Run AFTER training is complete.



import os
import pandas as pd
import matplotlib.pyplot as plt
import seaborn as sns
from config import plots_dir

os.makedirs(plots_dir, exist_ok=True)

RESULTS_CSV = 'runs/detect/models/finetuned/visdrone_yolov8s/results.csv'


def load_results():
    if not os.path.exists(RESULTS_CSV):
        print(f'ERROR: {RESULTS_CSV} not found.')
        print('Run train.py first!')
        exit()
    df = pd.read_csv(RESULTS_CSV)
    df.columns = df.columns.str.strip()   # remove any whitespace in column names
    print('Columns:', df.columns.tolist())
    return df


def plot_losses(df):
    colors = sns.color_palette('tab10', 10)
    fig, axs = plt.subplots(1, 3, figsize=(18, 5))

    for ax, train_col, val_col, title in zip(
        axs,
        ['train/box_loss', 'train/cls_loss', 'train/dfl_loss'],
        ['val/box_loss',   'val/cls_loss',   'val/dfl_loss'],
        ['Box Loss',       'Class Loss',     'DFL Loss']
    ):
        sns.lineplot(x='epoch', y=train_col, data=df, label='Train',      ax=ax, color=colors[0], linewidth=2)
        sns.lineplot(x='epoch', y=val_col,   data=df, label='Validation', ax=ax, color=colors[1], linewidth=2)
        ax.set(title=title, xlabel='Epoch', ylabel='Loss')
        ax.legend()

    plt.suptitle('Training vs Validation Loss', fontsize=14)
    plt.tight_layout()
    plt.savefig(os.path.join(plots_dir, 'losses.png'), dpi=100)
    plt.show()
    print(f'  Saved → {plots_dir}/losses.png')


def plot_map(df):
    colors = sns.color_palette('tab10', 10)
    fig, ax = plt.subplots(figsize=(10, 5))
    sns.lineplot(x='epoch', y='metrics/mAP50(B)',    data=df, label='mAP50',    ax=ax, color=colors[2], linewidth=2)
    sns.lineplot(x='epoch', y='metrics/mAP50-95(B)', data=df, label='mAP50-95', ax=ax, color=colors[3], linewidth=2)
    ax.set(title='mAP50 vs mAP50-95 over Epochs', xlabel='Epoch', ylabel='mAP')
    ax.legend()
    plt.tight_layout()
    plt.savefig(os.path.join(plots_dir, 'mAP.png'), dpi=100)
    plt.show()
    print(f'  Saved → {plots_dir}/mAP.png')


def plot_precision_recall(df):
    fig, ax = plt.subplots(figsize=(8, 8))
    sns.scatterplot(
        x='metrics/recall(B)', y='metrics/precision(B)',
        hue='epoch', size='epoch', palette='viridis',
        data=df, ax=ax
    )
    ax.set(title='Precision vs Recall (each dot = one epoch)',
           xlabel='Recall', ylabel='Precision')
    plt.tight_layout()
    plt.savefig(os.path.join(plots_dir, 'precision_recall.png'), dpi=100)
    plt.show()
    print(f'  Saved → {plots_dir}/precision_recall.png')


if __name__ == '__main__':
    print('=' * 50)
    print('  Plotting Training Results')
    print('=' * 50)

    df = load_results()
    plot_losses(df)
    plot_map(df)
    plot_precision_recall(df)

    print('\nAll plots saved to outputs/plots/')
